window.__QUIZ_DATA__=[{"id":"objective>Biology>1998>1","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Which of the following organisms exhibits both plant and animal characteristics?","images":[],"options":{"A":"Amoeba","B":"Spirogyra","C":"Mucor","D":"Euglena"},"answer":"D","explanation":"Euglena, genus of more than 1,000 species of single-celled flagellated (i.e., having a whiplike appendage) microorganisms that feature both plant and animal characteristics.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>2","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : ORGANIZATION OF LIFE","question":"Which of the following is not an organ?","images":[],"options":{"A":"Hair","B":"Tongue","C":"Rhizome","D":"Corn"},"answer":"A","explanation":"An organ is a group of tissues that perform a specific function or group of functions. Hair is not an organ but rather a part of the integumentary system that includes the skin, hair, nails, and exocrine glands. Hair is made of a tough protein called keratin and has various functions such as protection, regulation of body temperature, and facilitation of evaporation of perspiration. On the other hand, the tongue, rhizome, and corn are all considered organs because they are composed of different types of tissues and perform specific functions.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>3","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : THE CELL AND ITS ENVIRONMENT","question":"One major difference between osmosis and diffusion is that diffusion","images":[],"options":{"A":"does not need a semipermeable membrane","B":"does not take place in living tissues","C":"takes place only in a liquid medium","D":"takes place only in a gaseous medium"},"answer":"A","explanation":"Diffusion is the movement of molecules from an area of higher concentration to an area of lower concentration. It does not require a semipermeable membrane to occur. On the other hand, osmosis is a special type of diffusion that involves the movement of water molecules across a semipermeable membrane from an area of lower solute concentration to an area of higher solute concentration.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>4","subject":"Biology","year":"1998","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES","question":"Which of the following is a difference between mitosis and meiosis?","images":[],"options":{"A":"Alignment of chromosomes along the equitorial plane","B":"Replication of the chromosomes and the cell organelles","C":"Pairing of homologous chromosomes","D":"Formation of spindle fibers"},"answer":"C","explanation":"Differences between Mitosis and Meiosis: Pairing of homologous chromosomes (C): This is a key difference between mitosis and meiosis. During meiosis, homologous chromosomes (pairs of similar chromosomes from each parent) pair up in a process called synapsis during Prophase I. This pairing allows for crossing over, where genetic material is exchanged between homologous chromosomes, leading to genetic diversity. In mitosis, homologous chromosomes do not pair up; instead, each chromosome lines up individually along the metaphase plate.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>5","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Which of the following can be used for vegetative propagation?","images":[],"options":{"A":"Ginger stem","B":"Yam leaf","C":"Plantain roots","D":"Sweet potato tuber"},"answer":"A","explanation":"Ginger stem can be used for vegetative propagation. Ginger is one of the most popular spices in the world and comes from the underground stem of the ginger plant.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>6","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Which of the following is a method of artificial vegetative propagation?","images":[],"options":{"A":"Creeping stem","B":"Layering","C":"Corm","D":"Rhizome"},"answer":"B","explanation":"Artificial methods of vegetative propagation include cutting, layering, grafting, and tissue culture. All these structures grow naturally. The seed is always produced sexually and thus propagation via seeds is not a method of vegetative propagation.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>7","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"The above diagram represents a","images":["data:image/png;base64,"],"options":{"A":"longitudinal section of a stem","B":"longitudinal section of a root","C":"cross section of a root","D":"transverse section of stem"},"answer":"C","explanation":"The above diagram represents a cross section of a root. This is because the  -\tCortex (II): The layer just beneath the epidermis, involved in storage and transport.  -\tEndodermis (III): A distinctive single layer of cells separating the cortex from the vascular tissues, often with a Casparian strip, unique to roots.  -\tXylem and Phloem (IV): The arrangement of vascular tissues in a central column, typical of roots  -\tPericycle (V): Found just inside the endodermis, responsible for the formation of lateral roots.","marks":"1","difficulty":"3"},{"id":"objective>Biology>1998>8","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"The part labelled II in the diagram is the","images":["data:image/png;base64,"],"options":{"A":"epidermis","B":"cortex","C":"phloem","D":"xylem"},"answer":"B","explanation":"The part labelled II in the diagram is the cortex. The epidermis is the outermost layer of cells, labeled I in the diagram.  The cortex is the layer beneath the epidermis, consisting of multiple cells that store food and aid in the transport of water and nutrients.  The phloem and xylem are part of the vascular tissue, typically located in the central region of the root, which are not labeled as II.  The cuticle is a protective, waxy layer covering the epidermis, but it is not the same as the cortex.","marks":"1","difficulty":"3"},{"id":"objective>Biology>1998>9","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"The part labelled IV in the diagram is the","images":["data:image/png;base64,"],"options":{"A":"phloem","B":"pericycle","C":"cortex","D":"xylem"},"answer":"D","explanation":"The part labelled IV in the diagram is the xylem. The part labeled IV shows the central, star-shaped structure typical of xylem in a root cross-section.","marks":"1","difficulty":"3"},{"id":"objective>Biology>1998>10","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Which of the following is not a function of the blood?","images":[],"options":{"A":"Maintenance of body temperature","B":"Formation of clot","C":"Distribution of bile","D":"Transportation of excretory materials."},"answer":"C","explanation":"The function of blood includes maintenance of body temperature, formation of clot, and transportation of excretory materials. However, the distribution of bile is not a function of the blood. Bile is produced by the liver and stored in the gallbladder. It is then released into the small intestine to aid in the digestion of fats.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>11","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"Which of the following statements about the circulation of blood is not correct?","images":[],"options":{"A":"Deoxygenated blood flows in the heart through the vena cava","B":"Blood is pumped out of the heart through the aorta","C":"Oxygenated blood from the lung; is carried to the left auricle","D":"The oxygenated blood enters the lungs through the pulmonary vein"},"answer":"D","explanation":"The statement 'The oxygenated blood enters the lungs through the pulmonary vein' is incorrect. The pulmonary vein carries oxygenated blood from the lungs to the left atrium of the heart, not into the lungs. The other options correctly describe the circulation of blood.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>12","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : TRANSPORT SYSTEM","question":"A difference between the auricle and the ventricle of the mammalian heart is that the","images":[],"options":{"A":"ventricles carry deoxygenated blood","B":"ventricles do not have outlets","C":"auricles have no valves","D":"Walls of the ventricles are more muscular than that of the auricles"},"answer":"D","explanation":"A difference between the auricle and the ventricle of the mammalian heart is that the Walls of the ventricles are more muscular than that of the auricles. Walls of the ventricles are more muscular than that of the auricles: This is correct. The ventricles have thicker, more muscular walls because they need to pump blood to the entire body (left ventricle) or to the lungs (right ventricle), requiring more force compared to the auricles, which only need to pump blood into the ventricles.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>13","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Which of the following organism respires through the body surface","images":[],"options":{"A":"Man","B":"Fish","C":"Tridax","D":"Amoeba"},"answer":"D","explanation":"Amoeba respires through its body surface. This is because it is a single-celled organism and does not have specialized respiratory organs like lungs or gills. Instead, gases simply diffuse in and out of the cell across the cell membrane.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>14","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"The stomata of a leaf performs the same function as","images":[],"options":{"A":"spiracles of insects","B":"trachea of toads","C":"pharynx of man","D":"liver of man"},"answer":"A","explanation":"The stomata of a leaf performs the same function as spiracles of insects. Spiracles are respiratory openings found on the thorax and abdomen of insects. The spiracles are connected to trachea - tubes within the insect's body. Air enters the trachea via the spiracles and the oxygen then diffuses into the insect's body.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>15","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : RESPIRATORY SYSTEM","question":"Which of the following does not happen during inspiration?","images":[],"options":{"A":"intercostal muscles contract","B":"Ribs move forward","C":"Thoracic cavity increases","D":"Diaphragm relaxes"},"answer":"D","explanation":"During inspiration (inhalation), the diaphragm and intercostal muscles contract. This contraction causes the diaphragm to flatten and the rib cage to expand, increasing the volume of the thoracic cavity. As a result, air is drawn into the lungs. Therefore, the statement 'Diaphragm relaxes' does not happen during inspiration, making it the correct answer.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>16","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Which of the these is not an excretory product of plant?","images":[],"options":{"A":"Tannin","B":"Gum","C":"Alkaloid","D":"Sweat"},"answer":"D","explanation":"Plants do not have sweat glands, so they do not produce sweat. Sweat is a product of animal excretion, not plant excretion. Tannin, Gum, and Alkaloids are all excretory products of plants.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>17","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Which of these is not a function of the kidney?","images":[],"options":{"A":"Production of urine","B":"Maintenance of acid-base balance in the body","C":"Osmo-regulation","D":"Production of bile"},"answer":"D","explanation":"The kidney is responsible for the production of urine, maintenance of acid-base balance in the body, and osmo-regulation. However, the production of bile is a function of the liver, not the kidney.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>18","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"In which part of the kidney does ultrafiltration take place?","images":[],"options":{"A":"Bowman's capsule","B":"Distal convoluted tubule","C":"Proximal convoluted tubule","D":"Collecting duct"},"answer":"A","explanation":"Ultrafiltration in the kidney takes place in the Bowman's capsule. The Bowman's capsule is the initial part of the nephron in the kidney where blood is first filtered to form urine. The high pressure forces small molecules such as water, glucose, amino acids, urea and ions through the filter, from the blood in the glomerulus into the Bowman's capsule.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>19","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"Which of the following organs is concerned with detoxication of harmful compounds?","images":[],"options":{"A":"Kidney","B":"Lungs","C":"Gall bladder","D":"Liver"},"answer":"D","explanation":"Detoxification pathways in the liver The liver plays an important r\u00f4le in protecting the organism from potentially toxic chemical insults through its capacity to convert lipophiles into more water-soluble metabolites which can be efficiently eliminated from the body via the urine.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>20","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : HORMONAL COORDINATION","question":"The hormone that promotes secondary sexual characteristics in females is","images":[],"options":{"A":"insulin","B":"thyroxin","C":"testosterone","D":"oestrogen"},"answer":"D","explanation":"The hormone that promotes secondary sexual characteristics in females is oestrogen. Secondary sexual characteristics are features that distinguish the two sexes of a species, but that are not directly part of the reproductive system. In females, these characteristics include the development of breasts, widening of hips, and the growth of body hair. Oestrogen is the primary female sex hormone responsible for the development and regulation of the female reproductive system and secondary sex characteristics.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>21","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"The cell body in the diagram labelled","images":["data:image/png;base64,"],"options":{"A":"I","B":"II","C":"III","D":"IV"},"answer":"A","explanation":"Label I indicate the cell body (soma), which houses the nucleus and is responsible for maintaining the cell and integrating synaptic signals.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>22","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"The function of the part labelled II in the diagram is to","images":["data:image/png;base64,"],"options":{"A":"transmit impulse from one end of the cell to the other","B":"manufacture food for the cell","C":"protect the axon","D":"produce energy for the cell"},"answer":"C","explanation":"The function of the part labelled II in the diagram is to protect the axon.In a neuron, the part labeled II is likely the myelin sheath. The myelin sheath's main function is to insulate the axon and increase the speed at which electrical impulses (action potentials) travel along the axon.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>23","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : SENSE ORGANS","question":"The organ responsible for equalising air pressure in the ear is the","images":[],"options":{"A":"sacculus","B":"utriculus","C":"Eustachian tube","D":"ampulla"},"answer":"C","explanation":"The Eustachian tube is the organ responsible for equalising air pressure in the ear. It is a small canal that connects the middle ear to the nasopharynx, which consists of the upper throat and the back of the nasal cavity. It controls the pressure within the middle ear, making it equal with the air pressure outside the body. None of the other options (sacculus, utriculus, ampulla) perform this function.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>24","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Which of the following organisms lacks a reproductive organ?","images":[],"options":{"A":"Chlamydomonas","B":"Toad","C":"Pride of Barbados","D":"Cockroach"},"answer":"A","explanation":"Chlamydomonas lacks a reproductive organ. Chlamydomonas: This is a genus of green algae, which are single-celled organisms. They do not have specialized reproductive organs. Instead, they reproduce asexually by cell division or sexually by the fusion of gametes that are not part of specialized organs.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>25","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTIVE SYSTEM OF MAMMALS","question":"Which of the following mammalian features acts as a shock-absorber to the developing embryo?","images":[],"options":{"A":"Amniotic fluid","B":"Umbilical cord","C":"Placenta","D":"Amnion"},"answer":"A","explanation":"The amniotic fluid acts as a shock-absorber to the developing embryo. It is a clear, yellow fluid which is present in the amniotic sac. Its primary role is to provide a cushioning environment for the embryo, protecting it from physical shocks and impacts. The other options, umbilical cord, placenta, and amnion, have different roles in embryonic development. The umbilical cord connects the embryo to the placenta, allowing for the exchange of nutrients and waste. The placenta is an organ that connects the developing fetus to the uterine wall to allow nutrient uptake, waste elimination, and gas exchange. The amnion is a membrane that closely covers the embryo, forming a protective sac around it along with the amniotic fluid.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>26","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The collective name for the female parts of the flower is","images":[],"options":{"A":"gynoecium","B":"androecium","C":"ovary","D":"stigma"},"answer":"A","explanation":"The collective name for the female parts of a flower is 'gynoecium'. The gynoecium is the group of structures that form the female reproductive organ in flowers. It is typically composed of one or more carpels. The carpel is the individual unit of the gynoecium and has a stigma, style, and ovary.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>27","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"If the petals of a flowering plant are removed. Which of the following processes is likely to be affected?","images":[],"options":{"A":"Transpiration","B":"Pollination","C":"Germination","D":"Photosynthesis"},"answer":"B","explanation":"If the petals of a flowering plant are removed, the process likely to be affected is 'pollination'. Petals often play a key role in attracting pollinators to the flower. Without petals, pollinators may not be attracted to the flower, which can affect the process of pollination. Pollination is the transfer of pollen from the anther (male part) to the stigma (female part) of the same or a different flower.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>28","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The part labelled II in the diagram is the","images":["data:image/jpeg;base64,"],"options":{"A":"plumule","B":"endosperm","C":"radicle","D":"coleorhiza"},"answer":"B","explanation":"The diagram shows a monocot seed, likely a maize seed, with various parts labeled.   So, the part labeled II is the endosperm, which is the tissue that provides nutrition to the developing embryo.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>29","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The part labelled IV in the diagram is the","images":["data:image/png;base64,"],"options":{"A":"plumule","B":"endosperm","C":"radicle","D":"coleoptile"},"answer":"C","explanation":"Given the labeling in the diagram, the labeled part is the Radicle. The radical is part of the embryo that will develop into the root.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>30","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"The function of the part labelled V in the diagram is the","images":["data:image/png;base64,"],"options":{"A":"manufacture of food","B":"storage of food","C":"secretion of digestive enzymes","D":"protection of the radicle"},"answer":"D","explanation":"The function of the part labelled V in the diagram is the protection of the radicle.Given this identification, the function of the coleorhiza is to protect the radicle as it grows and emerges from the seed during germination.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>31","subject":"Biology","year":"1998","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"Which of the following is a feature of wind pollinated flowers?","images":[],"options":{"A":"Large and brightly coloured petals","B":"Possession of sweet scent","C":"Presence of nectar","D":"Smooth, light and numerous pollen grains"},"answer":"D","explanation":"Wind pollinated flowers, also known as anemophilous flowers, are characterized by their production of smooth, light, and numerous pollen grains. This is because the wind needs to carry the pollen grains from the male flower to the female flower, and having light and numerous pollen grains increases the chances of successful pollination. The other options are incorrect as they are characteristics of insect-pollinated flowers. Large and brightly coloured petals, sweet scent, and presence of nectar are all adaptations to attract insects for pollination, not features of wind pollinated flowers.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>32","subject":"Biology","year":"1998","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"In testing for starch in a leaf the function of alcohol is to","images":[],"options":{"A":"kill the cells of the leaf","B":"soften the veins of the leaf","C":"aid iodine to penetrate the cells","D":"extract the chlorophyll from the leaf"},"answer":"D","explanation":"Starch is a carbohydrate that consists of many glucose units attached to glycosidic bonds. When a leaf is boiled in alcohol like ethanol, it helps to extract chlorophyll and help remove the green color of the leaves.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>33","subject":"Biology","year":"1998","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"Which of the following processes removes CO2 from the atmosphere?","images":[],"options":{"A":"Respiration","B":"Photosynthesis","C":"Transpiration","D":"Excretion"},"answer":"B","explanation":"Photosynthesis is the process by which green plants and some other organisms use sunlight to synthesize foods with the help of chlorophyll pigments. During this process, plants absorb carbon dioxide (CO2) from the atmosphere and release oxygen. Therefore, photosynthesis removes CO2 from the atmosphere.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>34","subject":"Biology","year":"1998","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : NITROGEN CYCLE","question":"The role of bacteria in the nitrogen cycle includes the following except","images":[],"options":{"A":"fixing atmospheric nitrogen","B":"converting ammonia to nitrites","C":"converting nitrites to nitrates","D":"converting carbohydrates to carbondioxide"},"answer":"D","explanation":"The role of bacteria in the nitrogen cycle includes fixing atmospheric nitrogen, converting ammonia to nitrites, and converting nitrites to nitrates. However, converting carbohydrates to carbon dioxide is not a role of bacteria in the nitrogen cycle. This process is part of the carbon cycle, not the nitrogen cycle.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>35","subject":"Biology","year":"1998","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"The mode of nutrition which describes feeding habit in animals is","images":[],"options":{"A":"autotrophic","B":"holozoic","C":"holophytic","D":"saprophytic"},"answer":"B","explanation":"Holozoic nutrition (Greek: holo-whole ; zoikos-of animals) is a type of heterotrophic nutrition that is characterized by the internalization and internal processing of liquids or solid food particles.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>36","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : CLASSIFICATION","question":"Which of the following organisms has homodont dentition?","images":[],"options":{"A":"Rabbit","B":"Man","C":"Sheep","D":"Lizard"},"answer":"D","explanation":"Homodont dentition: in this type of dentition, the organism possesses or have the same types or sets of teeth. In this types of dentition, there are no specialized set of teeth for a particular type of function. All the teeth of a typical homodont dentition are of the same sizes, shape and functions.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>37","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : EXCRETORY SYSTEMS","question":"The pancreatic duct opens into the","images":[],"options":{"A":"caecum","B":"colon","C":"ileum","D":"duodenum"},"answer":"D","explanation":"The pancreatic duct opens into the duodenum. The pancreas is an organ in the digestive system that produces important enzymes and hormones that help break down foods. The pancreatic duct is a tube that runs from the pancreas and carries the digestive enzymes produced by endocrine cells to the duodenum, which is the first part of the small intestine. Therefore, the correct answer is duodenum.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>38","subject":"Biology","year":"1998","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"The enzyme that acts on milk in the stomach is","images":[],"options":{"A":"invertase","B":"trypsin","C":"diastase","D":"renin"},"answer":"D","explanation":"Milk protein is acted upon by a gastric enzyme known as rennin which digests these milk proteins called caseinogen. It is also known as chymosin and is activated by the HCl present in the stomach where it is converted from inactive prorenin to rennin. It converts the milk protein caseinogen to casein and finally to calcium paracasein thus causing curdling.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>39","subject":"Biology","year":"1998","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : MODES OF NUTRITION","question":"Which of the following plants is a carnivore?","images":[],"options":{"A":"Desmodium","B":"Sundew","C":"Mushroom","D":"Platycerium"},"answer":"B","explanation":"Sundew, also known as Drosera, is a genus of carnivorous plants with at least 194 species. They grow in nutrient-poor environments and get their nutrients from insects they trap on their leaves","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>40","subject":"Biology","year":"1998","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : FEEDING HABITS","question":"Hydra feeds by","images":[],"options":{"A":"digesting its food extra cellularly","B":"absorbing food digested by other organisms","C":"symbiotic association","D":"masticating the food particles"},"answer":"A","explanation":"Hydra is a simple multicellular organism that feeds by digesting its food extracellularly. This means that the digestion of food occurs outside the cells in the gastrovascular cavity. The cells lining the gastrovascular cavity secrete digestive enzymes that break down the food into simpler substances that can be absorbed by the cells. Therefore, the correct answer is option 1: digesting its food extracellularly.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>41","subject":"Biology","year":"1998","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Which of the following contains a reducing sugar?","images":[],"options":{"A":"Milk","B":"Cassava","C":"rice","D":"Beans"},"answer":"C","explanation":"Milk contains a significant amount of lactose, a disaccharide that is a reducing sugar. In fact, lactose is the primary carbohydrate in milk, making it a rich source of reducing sugars.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>42","subject":"Biology","year":"1998","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : SIMPLE MEASUREMENT OF ECOLOGICAL FACTORS","question":"Which of the following instrument can be used to measure relative humidity?","images":[],"options":{"A":"Anemometer","B":"Hygrometer","C":"Wind gauge","D":"Barometer"},"answer":"B","explanation":"Relative humidity is the amount of moisture in the air compared to the maximum amount of moisture the air could hold at the same temperature. This is measured using a hygrometer. An anemometer measures wind speed, a wind gauge is another name for an anemometer, and a barometer measures atmospheric pressure.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>43","subject":"Biology","year":"1998","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"In a food chain, each stage in the chain is a","images":[],"options":{"A":"chain level","B":"web level","C":"consumption level","D":"trophic level"},"answer":"D","explanation":"In a food chain, each stage is referred to as a trophic level. Trophic levels represent the position an organism occupies in a food chain. It starts with producers at the first level, followed by consumers at the subsequent levels. The term 'trophic' is derived from the Greek word 'trophe', meaning food or feeding. None of the other options correctly represent the stages in a food chain.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>44","subject":"Biology","year":"1998","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOSYSTEM","question":"The diagram above illustrates","images":["data:image/png;base64,"],"options":{"A":"the size of various organisms","B":"types of organisms in a habitat","C":"the flow of energy in a habitat","D":"the hierarchy of organisms in a habitat"},"answer":"C","explanation":"The diagram above illustrates the flow of energy in a habitat. The diagram represents a pyramid structure showing different levels of organisms, with each level representing who eats whom in an ecosystem. The base starts with phytoplankton, which are producers, and it progresses up to kingfishers, which are top predators. This arrangement depicts the transfer of energy through the ecosystem.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>45","subject":"Biology","year":"1998","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"Which of these organisms occupies the 3rd trophic  level?","images":["data:image/png;base64,"],"options":{"A":"King fisher","B":"Small fish","C":"Phytoplankton","D":"Big fish"},"answer":"B","explanation":"Small fish occupies the 3rd trophic level. In a food chain, the trophic levels are defined as follows:  -\tFirst trophic level: Producers (e.g., Phytoplankton)  -\tSecond trophic level: Primary consumers (e.g., Tadpole)  -\tThird trophic level: Secondary consumers (e.g., Small fish)  -\tFourth trophic level: Tertiary consumers (e.g., Big fish)  -\tFifth trophic level: Quaternary consumers (e.g., Kingfisher)  Based on the diagram provided, the organism occupying the third trophic level is the Small fish.  Small fish consume tadpoles, which are primary consumers.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>46","subject":"Biology","year":"1998","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : FOOD WEBS AND TROPHIC LEVELS","question":"Which of these organisms is a herbivore?","images":["data:image/png;base64,"],"options":{"A":"Tadpole","B":"Phytoplankton","C":"King Fisher","D":"Small fish"},"answer":"A","explanation":"In the context of the provided food chain:  - Phytoplankton are producers (autotrophs) and not herbivores.  - Tadpoles are primary consumers that feed on phytoplankton and other plant materials, making them herbivores.  - Small fish, big fish, and kingfishers are consumers that feed on other animals, so they are not herbivores. Therefore, the correct answer is Tadpole","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>47","subject":"Biology","year":"1998","type":"Objective","topic":"ECOLOGICAL MANAGEMENT : ADAPTATION OF ORGANISMS TO HABITATS.","question":"The presence of stilt and breathing roots are features of plants found in the","images":[],"options":{"A":"tropical rain forests","B":"fresh water swamp forests","C":"mangrove forests","D":"southern guinea savanna"},"answer":"C","explanation":"The presence of stilt and breathing roots are characteristics of plants found in mangrove forests. Mangrove forests are found in tropical and subtropical tidal areas, and they are characterized by the presence of salt-tolerant trees and shrubs that can grow in the intertidal zone, where land and sea meet.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>48","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : CELL STRUCTURE AND FUNCTIONS OF CELL COMPONENTS.","question":"Excessive loss of water from the leaf is prevented by the","images":[],"options":{"A":"vascular bundle","B":"cuticle","C":"midrib","D":"parenchyma"},"answer":"B","explanation":"Excessive loss of water from the leaf is prevented by the cuticle. The cuticle is a waxy layer present on the surface of the leaves, stems, and other aerial parts of the plants. It is hydrophobic (water-repelling) in nature and thus prevents the loss of water from the plant surfaces by evaporation.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>49","subject":"Biology","year":"1998","type":"Objective","topic":"ECOLOGY OF POPULATION : ECOLOGICAL SUCCESSION","question":"Which of the following organisms will be a colonizing species of a heap of moist sub soil?","images":[],"options":{"A":"Green algae","B":"Ferns","C":"White mangrove","D":"Snails"},"answer":"A","explanation":"A colonizing species is the first species to colonize previously disrupted or damaged ecosystems, beginning a chain of ecological succession that ultimately leads to a more biodiverse steady-state ecosystem. In the case of a heap of moist sub soil, green algae would be the first to colonize. This is because green algae are pioneer species, which are hardy species which are the first to colonize previously biodiverse steady-state ecosystems. They are capable of living in harsh conditions and can photosynthesize, which allows them to start the process of succession.  The other options are not typical colonizing species of a heap of moist subsoil:  Ferns require more complex soil and light to grow.  White mangrove is a coastal plant that requires salty water and cannot grow in subsoil.  Snails require a more developed ecosystem with vegetation and organic matter.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>50","subject":"Biology","year":"1998","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL COMPONENTS","question":"The earthworm is important because","images":[],"options":{"A":"its body is always moist","B":"each of its segments has chaetae","C":"It has a clitellum","D":"it aerates the soil"},"answer":"D","explanation":"The earthworm is important because it aerates the soil. This is done as the earthworm burrows through the soil, creating tunnels that allow air to penetrate. This process is crucial for the health of the soil as it promotes the circulation of oxygen, which is necessary for the survival of many soil organisms. The other options, while true characteristics of earthworms, do not explain their importance.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>51","subject":"Biology","year":"1998","type":"Objective","topic":"PLANT AND ANIMAL NUTRITION : PLANT NUTRITION","question":"which of the following plant parts is not a storage organ?","images":[],"options":{"A":"Carrot root","B":"Sugarcane stem","C":"Onion leaf","D":"Banana stem"},"answer":"C","explanation":"Storage organs in plants are parts of the plant that store nutrients and energy for the plant to use during periods of less-than-optimal conditions. These include roots, stems, and tubers. In the given options, carrot root, sugarcane stem, and banana stem are all examples of storage organs. However, onion leaf is not a storage organ. The onion bulb, not the leaf, is the storage organ in onions. Therefore, the correct answer is 'Onion leaf'.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>52","subject":"Biology","year":"1998","type":"Objective","topic":"MICROORGANISMS: MAN AND HEALTH : PUBLIC HEALTH","question":"Which of the following statements about poliomyelitis is not correct. It","images":[],"options":{"A":"is a bacterial disease","B":"is capable of paralysing the limbs","C":"can be prevented by immunization","D":"is an infant disease"},"answer":"A","explanation":"Poliomyelitis, also known as polio, is not a bacterial disease but a viral disease. It is caused by the poliovirus. The virus can cause paralysis by infecting and destroying motor neurons in the spinal cord. It can be prevented by immunization, and it affects both children and adults, not just infants.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>53","subject":"Biology","year":"1998","type":"Objective","topic":"BASIC ECOLOGICAL CONCEPTS : ECOLOGICAL MANAGEMENT","question":"Oil is sprayed over stagnant water in which mosquitoes breed in order to","images":[],"options":{"A":"provide landing surface for the adult","B":"prevent larva or pupa from attaching itself to the surface","C":"prevent the water from overheating","D":"lubricate the larva for easy movement"},"answer":"B","explanation":"Oil is sprayed over stagnant water where mosquitoes breed to prevent the larvae or pupa from attaching itself to the surface. This is because mosquito larvae and pupae breathe through tubes located on their abdominal segments. When oil is sprayed on the water surface, it forms a thin layer that prevents the larvae and pupae from getting air, causing them to suffocate and die.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>54","subject":"Biology","year":"1998","type":"Objective","topic":"CONCEPT OF LIVING : TISSUES AND SUPPORTING SYSTEMS","question":"In animals the main protective covering is found in the","images":[],"options":{"A":"adipose tissues","B":"epithelial tissues","C":"bone tissues","D":"connective tissues"},"answer":"B","explanation":"In animals, the main protective covering is found in the epithelial tissues. Epithelial tissues cover the whole surface of the body. They are made up of cells closely packed and ranged in one or more layers. This tissue is specialized to form the covering or lining of all internal and external body surfaces. Epithelial tissues that cover the skin, the surface of the eyes, the lining of the mouth, throat, stomach, intestines, the urinary tract, the genital tract, and the respiratory tract are all derived from the ectoderm and endoderm with a small contribution from the mesoderm, forming the endothelium, a specialized type of epithelium that composes the lining of blood and lymphatic vessels. Therefore, they serve as the main protective covering in animals.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>55","subject":"Biology","year":"1998","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : CHROMOSOMES","question":"How many chromosomes will be present in a gamete if the somatic cell has eight(8) chromosomes?","images":[],"options":{"A":"4","B":"6","C":"8","D":"10"},"answer":"A","explanation":"In sexually reproducing organisms, the number of chromosomes in a gamete is half the number of chromosomes in a somatic cell. This is because gametes are formed through a process called meiosis, which reduces the number of chromosomes by half. Therefore, if a somatic cell has 8 chromosomes, a gamete will have 4 chromosomes.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>56","subject":"Biology","year":"1998","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)","question":"In a plant of genotype Tt, what is the probability that a gamete will contain gene t?","images":[],"options":{"A":"1\\2","B":"3\\4","C":"1\\8","D":"1\\6"},"answer":"A","explanation":"In a heterozygous organism (Tt), the probability of a gamete containing either allele (T or t) is 1/2. This is because during meiosis, the two alleles for each gene segregate from each other, so each gamete carries only one allele for each gene. Therefore, the probability that a gamete will contain the gene t is 1/2.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>57","subject":"Biology","year":"1998","type":"Objective","topic":"BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)","question":"In a cross involving a heterozygous red flowered plant (Rr) and a white flowered plant (rr). what is the probability that the offspring will be Rr?","images":[],"options":{"A":"1","B":"1\\2","C":"1\\4","D":"3\\4"},"answer":"B","explanation":"In a cross involving a heterozygous red flowered plant (Rr) and a white flowered plant (rr), the possible combinations of alleles in the offspring are RR, Rr, rR, and rr. The probability of getting a heterozygous red flowered plant (Rr) is therefore 1 out of 4 or 1/2. This is because the heterozygous red flowered plant can be produced in two ways (Rr or rR), and there are four possible outcomes. Therefore, the probability is 2/4, which simplifies to 1/2.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>58","subject":"Biology","year":"1998","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Termites are called social insects because","images":[],"options":{"A":"the nests are built by the nasute soldiers","B":"they live together in communities","C":"the queen allocates duties to the workers","D":"the king and queen do mate"},"answer":"B","explanation":"Termites are called social insects because they live together in communities. Ants, Honey bees and termites are called social insects because they live and work together in groups.","marks":"1","difficulty":"1"},{"id":"objective>Biology>1998>59","subject":"Biology","year":"1998","type":"Objective","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"Which of the following makes up the bee caste","images":[],"options":{"A":"Soldiers and Queen","B":"Drones, soldiers and workers","C":"Queen, workers and soldiers","D":"Queen, drones and workers"},"answer":"D","explanation":"A bee caste is made up of the Queen, drones, and workers. The Queen is the only sexually mature female in the hive and her primary role is to reproduce. Drones are male bees, and their primary role is to mate with the Queen. Workers are non-reproducing females who perform all the tasks necessary for the survival of the hive. Therefore, the correct answer is 'Queen, drones and workers'.","marks":"1","difficulty":"2"},{"id":"objective>Biology>1998>60","subject":"Biology","year":"1998","type":"Objective","topic":"EVOLUTION : ADAPTIVE COLOURATION","question":"Which of the following examples best describes camouflagic colouration in organisms?","images":[],"options":{"A":"A butterfly which has a real colouration on the wing","B":"A green snake in a green grass","C":"zebra with vertical stripes on the body","D":"Certain tree frogs with bright colour patterns"},"answer":"B","explanation":"Cryptic or concealing or camouflage enables the organisms to blend with it's back ground and be less visible to predators. E.g the green leaf-like mantis, dark colour on the dorsal side and silvery white color on the ventral side as in most fish, changing the colour pattern of the body to blend with that of the general surrounding as in green snake in green grass.","marks":"1","difficulty":"2"}];